+  NotificationAdapter,
+  NotificationPayload,
+  NotificationResult,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+/**
+ * Represents an SMS message ready for sending.
+ */
+export interface SmsMessage {
+  to: string;
+  from: string;
+  body: string;
+}
+
+/**
+ * Transport interface for actually sending SMS messages.
+ * Implement this for Twilio, AWS SNS, etc.
+ */
+export interface SmsTransport {
+  sendSms(message: SmsMessage): Promise<{ messageId: string }>;
+}
+
+/**
+ * Configuration for the SMS adapter.
+ */
+export interface SmsAdapterConfig {
+  /** Sender phone number or short code. */
+  fromNumber: string;
+  /** SMS transport implementation. If not provided, uses a logging-only transport. */
+  transport?: SmsTransport;
+}
+
+/**
+ * Maximum length for an SMS message body (standard SMS limit).
+ */
+const SMS_MAX_LENGTH = 160;
+
+/**
+ * Format a notification payload into a short SMS-appropriate text body.
+ * SMS messages are truncated to 160 characters.
+ */
+export function formatSmsBody(payload: NotificationPayload): string {
+  const text = `${payload.subject}: ${payload.body}`;
+  if (text.length <= SMS_MAX_LENGTH) {
+    return text;
+  }
+  return text.slice(0, SMS_MAX_LENGTH - 3) + '...';
+}
