+ * A logging-only transport used when no real transport is configured.
+ * Useful for development and testing.
+ */
+class LoggingTransport implements SmsTransport {
+  private logger = new Logger('SmsLoggingTransport');
+  private sentMessages: SmsMessage[] = [];
+
+  async sendSms(message: SmsMessage): Promise<{ messageId: string }> {
+    const messageId = `sms-log-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
+    this.logger.info(`[DRY RUN] SMS to=${message.to} from=${message.from} id=${messageId}`);
+    this.sentMessages.push(message);
+    return { messageId };
+  }
+
+  getSentMessages(): SmsMessage[] {
+    return [...this.sentMessages];
+  }
+}
