+    try {
+      const message = this.formatMessage(payload);
+      this.logger.info(`Sending SMS to ${message.to} (from: ${this.config.fromNumber})`);
+
+      const result = await this.transport.sendSms(message);
+      this.logger.info(`SMS sent successfully: messageId=${result.messageId}`);
+
+      return {
+        success: true,
+        channel: this.channel,
+      };
+    } catch (err: unknown) {
+      const errorMessage = err instanceof Error ? err.message : 'Unknown SMS transport error';
+      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${errorMessage}`);
+
+      return {
+        success: false,
+        channel: this.channel,
+        error: errorMessage,
+      };
+    }
+  }
+}

