/**
 * SMS notification adapter.
 *
 * Implements the NotificationAdapter interface for SMS delivery.
 * Formats notification payloads into short text messages and sends them
 * via a pluggable SMS transport (Twilio, AWS SNS, etc.).
 *
 * CONSTRAINT: All adapters must implement the NotificationAdapter interface
 * from src/models/notification.ts. Register adapters with NotificationService
 * via registerAdapter().
 *
 * NOTE: User preferences were originally designed for email-only channels.
 * The UserPreferences model (src/models/user-preferences.ts) and
 * PreferencesService (src/services/preferences.service.ts) only support
 * email preferences. They need to be updated to support per-channel
 * preferences (SMS opt-in/out, SMS frequency, etc.) before SMS notifications
 * can respect user preferences. See SMS_PREFERENCES_TODO.md for details.
 */

import type {
  NotificationAdapter,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Represents an SMS message ready for sending.
 */
export interface SmsMessage {
  to: string;
  from: string;
  body: string;
}

/**
 * Transport interface for actually sending SMS messages.
 * Implement this for Twilio, AWS SNS, etc.
 */
export interface SmsTransport {
  sendSms(message: SmsMessage): Promise<{ messageId: string }>;
}

/**
 * Configuration for the SMS adapter.
 */
export interface SmsAdapterConfig {
  /** Sender phone number or short code. */
  fromNumber: string;
  /** SMS transport implementation. If not provided, uses a logging-only transport. */
  transport?: SmsTransport;
}

/**
 * Maximum length for an SMS message body (standard SMS limit).
 */
const SMS_MAX_LENGTH = 160;

/**
 * Format a notification payload into a short SMS-appropriate text body.
 * SMS messages are truncated to 160 characters.
 */
export function formatSmsBody(payload: NotificationPayload): string {
  const text = `${payload.subject}: ${payload.body}`;
  if (text.length <= SMS_MAX_LENGTH) {
    return text;
  }
  return text.slice(0, SMS_MAX_LENGTH - 3) + '...';
}

/**
 * A logging-only transport used when no real transport is configured.
 * Useful for development and testing.
 */
class LoggingTransport implements SmsTransport {
  private logger = new Logger('SmsLoggingTransport');
  private sentMessages: SmsMessage[] = [];

  async sendSms(message: SmsMessage): Promise<{ messageId: string }> {
    const messageId = `sms-log-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    this.logger.info(`[DRY RUN] SMS to=${message.to} from=${message.from} id=${messageId}`);
    this.sentMessages.push(message);
    return { messageId };
  }

  getSentMessages(): SmsMessage[] {
    return [...this.sentMessages];
  }
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private transport: SmsTransport;

  constructor(private config: SmsAdapterConfig) {
    this.transport = config.transport ?? new LoggingTransport();
  }

  /**
   * Build an SmsMessage from a notification payload.
   */
  formatMessage(payload: NotificationPayload): SmsMessage {
    return {
      to: payload.recipient.trim(),
      from: this.config.fromNumber,
      body: formatSmsBody(payload),
    };
  }

  /**
   * Send a notification via SMS.
   *
   * Formats the notification as a short text message and dispatches
   * via the configured transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const message = this.formatMessage(payload);
      this.logger.info(`Sending SMS to ${message.to} (from: ${this.config.fromNumber})`);

      const result = await this.transport.sendSms(message);
      this.logger.info(`SMS sent successfully: messageId=${result.messageId}`);

      return {
        success: true,
        channel: this.channel,
      };
    } catch (err: unknown) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown SMS transport error';
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${errorMessage}`);

      return {
        success: false,
        channel: this.channel,
        error: errorMessage,
      };
    }
  }
}

